//! Build/dev tooling for exa-agent-cli. Run as `cargo xtask <cmd>`.
//!
//! Implemented: `vendor-spec [--check]`, `generate-skill [--check]`, `ci`, `ergonomics`,
//! `smoke`, `phase-gate N`.
//! The registry itself is generated by `build.rs` at build time (D9).

use std::collections::BTreeMap;
use std::path::{Path, PathBuf};
use std::process::Command;

use anyhow::{anyhow, bail, Context, Result};

const EXA_SPEC_URL: &str = "https://exa.ai/docs/exa-spec.json";
const ADMIN_SPEC_URL: &str = "https://exa.ai/docs/team-management-spec.yaml";

const EXA_SPEC: &str = "openapi/exa-openapi.json";
const ADMIN_SPEC: &str = "openapi/team-management.json";
const OVERLAY: &str = "openapi/overlay.toml";
const GENERATED_SKILL: &str = "work/generated/exa-agent-cli/SKILL.md";

// Verified spec identity (D22, 2026-06-29). The Phase-1 goldens freeze these.
const EXA_TITLE: &str = "Exa Public API";
const EXA_VERSION: &str = "2.0.0";
const ADMIN_TITLE: &str = "Team Management API";
const ADMIN_VERSION: &str = "1.0.0";

fn main() -> Result<()> {
    let args: Vec<String> = std::env::args().skip(1).collect();
    let cmd = args.first().map(String::as_str).unwrap_or("help");
    let rest = &args[args.len().min(1)..];
    match cmd {
        "vendor-spec" => vendor_spec(rest.contains(&"--check".to_string())),
        "generate-registry" => generate_registry(rest.contains(&"--check".to_string())),
        "generate-skill" => generate_skill(rest.contains(&"--check".to_string())),
        "ci" => ci(),
        "ergonomics" => ergonomics(),
        "smoke" => smoke(rest),
        "phase-gate" => phase_gate(rest.first().map(String::as_str)),
        "help" | "--help" | "-h" => {
            print_help();
            Ok(())
        }
        other => {
            print_help();
            bail!("unknown xtask command: {other}");
        }
    }
}

fn print_help() {
    eprintln!(
        "xtask commands:\n  \
         vendor-spec [--check]   fetch/verify the vendored OpenAPI specs (Phase-0 gate)\n  \
         generate-registry [--check] build registry; --check compares normalized fixed-env emission\n  \
         generate-skill [--check] regenerate/check the canonical agent skill offline\n  \
         ci                       offline gate: fmt --check, clippy -D warnings, test\n  \
         ergonomics               Wave 6 intent and self-description harness\n  \
         smoke [--budget N]       live read-only smoke with a cost ceiling (default 0.05)\n  \
         phase-gate N             run the tests/snapshots required for Phase N"
    );
}

fn repo_root() -> Result<PathBuf> {
    // xtask runs from the workspace root under `cargo xtask`; fall back to CARGO_MANIFEST_DIR/..
    let out = Command::new("git")
        .args(["rev-parse", "--show-toplevel"])
        .output();
    if let Ok(o) = out {
        if o.status.success() {
            let p = String::from_utf8_lossy(&o.stdout).trim().to_string();
            if !p.is_empty() {
                return Ok(PathBuf::from(p));
            }
        }
    }
    Ok(std::env::current_dir()?)
}

fn vendor_spec(check_only: bool) -> Result<()> {
    let root = repo_root()?;
    if check_only {
        verify_spec(&root.join(EXA_SPEC), EXA_TITLE, EXA_VERSION)?;
        verify_spec(&root.join(ADMIN_SPEC), ADMIN_TITLE, ADMIN_VERSION)?;
        verify_overlay(&root)?;
        println!("vendor-spec --check: OK (specs parse, identity verified, overlay consistent)");
        return Ok(());
    }

    // Live re-vendor. The Exa public spec is served as JSON; the admin spec as YAML, so it is
    // normalized to JSON via ruby (no YAML parser ships in the binary, D21).
    fetch_json(EXA_SPEC_URL, &root.join(EXA_SPEC))?;
    fetch_yaml_as_json(ADMIN_SPEC_URL, &root.join(ADMIN_SPEC))?;
    verify_spec(&root.join(EXA_SPEC), EXA_TITLE, EXA_VERSION)?;
    verify_spec(&root.join(ADMIN_SPEC), ADMIN_TITLE, ADMIN_VERSION)?;
    println!("vendor-spec: re-vendored and verified {EXA_SPEC} + {ADMIN_SPEC}");
    Ok(())
}

fn fetch_json(url: &str, dest: &Path) -> Result<()> {
    let out = Command::new("curl")
        .args(["-sS", "-L", "--fail", "--max-time", "60", url])
        .output()
        .context("run curl")?;
    if !out.status.success() {
        bail!(
            "curl failed for {url}: {}",
            String::from_utf8_lossy(&out.stderr)
        );
    }
    // Round-trip through serde_json to normalize whitespace deterministically.
    let v: serde_json::Value = serde_json::from_slice(&out.stdout).context("parse fetched JSON")?;
    std::fs::write(dest, serde_json::to_string_pretty(&v)? + "\n")?;
    Ok(())
}

fn fetch_yaml_as_json(url: &str, dest: &Path) -> Result<()> {
    let script = format!(
        "require 'yaml'; require 'json'; require 'open-uri'; \
         d = YAML.safe_load(URI.open({url:?}).read, aliases: true); \
         File.write({dest:?}, JSON.pretty_generate(d) + \"\\n\")",
        url = url,
        dest = dest.to_string_lossy(),
    );
    let out = Command::new("ruby")
        .args(["-e", &script])
        .output()
        .context("run ruby (YAML->JSON conversion needs ruby on PATH)")?;
    if !out.status.success() {
        bail!(
            "ruby YAML->JSON failed: {}",
            String::from_utf8_lossy(&out.stderr)
        );
    }
    Ok(())
}

fn verify_spec(path: &Path, want_title: &str, want_version: &str) -> Result<()> {
    let bytes = std::fs::read(path).with_context(|| format!("read {}", path.display()))?;
    let v: serde_json::Value =
        serde_json::from_slice(&bytes).with_context(|| format!("parse {}", path.display()))?;
    let title = v
        .pointer("/info/title")
        .and_then(|x| x.as_str())
        .unwrap_or("");
    let version = v
        .pointer("/info/version")
        .and_then(|x| x.as_str())
        .unwrap_or("");
    if title != want_title || version != want_version {
        bail!(
            "{}: identity mismatch — got {title:?} {version:?}, want {want_title:?} {want_version:?}",
            path.display()
        );
    }
    Ok(())
}

/// Every overlay operation must resolve to a spec op (or be overlay-defined). This is the
/// offline half of the registry-consistency guarantee (arch §3).
fn verify_overlay(root: &Path) -> Result<()> {
    let overlay: toml::Value = toml::from_str(&std::fs::read_to_string(root.join(OVERLAY))?)
        .context("parse overlay.toml")?;
    let spec_ops = collect_op_ids(&root.join(EXA_SPEC))?
        .into_iter()
        .chain(collect_op_ids(&root.join(ADMIN_SPEC))?)
        .collect::<BTreeMap<_, _>>();

    let ops = overlay
        .get("operations")
        .and_then(|x| x.as_table())
        .ok_or_else(|| anyhow!("overlay.toml has no [operations] table"))?;

    let mut problems = Vec::new();
    for (oid, meta) in ops {
        let defined = meta
            .get("defined_by_overlay")
            .and_then(|x| x.as_bool())
            .unwrap_or(false);
        if !defined && !spec_ops.contains_key(oid.as_str()) {
            problems.push(format!("overlay op {oid:?} not found in any vendored spec"));
        }
        if meta.get("cli_path").and_then(|x| x.as_str()).is_none() {
            problems.push(format!("overlay op {oid:?} missing cli_path"));
        }
    }
    if !problems.is_empty() {
        bail!("overlay inconsistencies:\n  {}", problems.join("\n  "));
    }
    Ok(())
}

fn collect_op_ids(path: &Path) -> Result<Vec<(String, ())>> {
    let v: serde_json::Value = serde_json::from_slice(&std::fs::read(path)?)?;
    let mut out = Vec::new();
    if let Some(paths) = v.get("paths").and_then(|p| p.as_object()) {
        for methods in paths.values() {
            let Some(methods) = methods.as_object() else {
                continue;
            };
            for op in methods.values() {
                if let Some(oid) = op.get("operationId").and_then(|x| x.as_str()) {
                    out.push((oid.to_string(), ()));
                }
            }
        }
    }
    Ok(out)
}

fn generate_registry(check_only: bool) -> Result<()> {
    run("cargo", &["build", "--quiet"])?;
    if check_only {
        let args = [
            "run",
            "--quiet",
            "--bin",
            "exa-agent",
            "--",
            "capabilities",
            "--compact",
        ];
        let mut first = run_json_value_offline("cargo", &args, "exa.cli.capabilities.v1")?;
        let mut second = run_json_value_offline("cargo", &args, "exa.cli.capabilities.v1")?;
        first
            .as_object_mut()
            .expect("capabilities object")
            .remove("build");
        second
            .as_object_mut()
            .expect("capabilities object")
            .remove("build");
        if first != second {
            bail!("registry emission is not deterministic under fixed SOURCE_DATE_EPOCH");
        }
        println!("generate-registry --check: OK (normalized fixed-environment capabilities match)");
    } else {
        println!("generate-registry: built (registry.rs emitted to OUT_DIR by build.rs)");
    }
    Ok(())
}

fn generate_skill(check_only: bool) -> Result<()> {
    let root = repo_root()?;
    let guide = run_json_value_offline(
        "cargo",
        &[
            "run",
            "--quiet",
            "--bin",
            "exa-agent",
            "--",
            "robot-docs",
            "guide",
            "--compact",
        ],
        "exa.cli.robot_docs.v1",
    )?;
    let examples = run_json_value_offline(
        "cargo",
        &[
            "run",
            "--quiet",
            "--bin",
            "exa-agent",
            "--",
            "robot-docs",
            "examples",
            "--task",
            "search",
            "--compact",
        ],
        "exa.cli.robot_docs.v1",
    )?;
    let mut skill = String::from(
        "---\nname: exa-agent-cli\ndescription: Use the exa-agent CLI for Exa search, contents, answer, context, similar, Websets, monitors, and agent workflows.\n---\n\n# exa-agent CLI skill\n\nGenerated by `cargo xtask generate-skill`; do not edit by hand.\n\n## Guidance\n",
    );
    for line in guide["guidance"]
        .as_array()
        .context("robot guide guidance array")?
    {
        skill.push_str("- ");
        skill.push_str(line.as_str().context("robot guide string")?);
        skill.push('\n');
    }
    skill.push_str("\n## Offline examples\n\n");
    for line in examples["examples"]
        .as_array()
        .context("robot examples array")?
    {
        skill.push_str("```sh\n");
        skill.push_str(line.as_str().context("robot example string")?);
        skill.push_str("\n```\n");
    }

    let path = root.join(GENERATED_SKILL);
    if check_only {
        let existing = std::fs::read_to_string(&path)
            .with_context(|| format!("read generated skill {}", path.display()))?;
        if existing != skill {
            bail!("generated skill is stale; run `cargo xtask generate-skill`");
        }
    } else {
        std::fs::write(&path, skill)
            .with_context(|| format!("write generated skill {}", path.display()))?;
    }
    println!("generate-skill: OK");
    Ok(())
}

fn ci() -> Result<()> {
    run("cargo", &["fmt", "--all", "--", "--check"])?;
    run_env(
        "cargo",
        &["xtask", "generate-registry", "--check"],
        &[("EXA_AGENT_NO_NETWORK", "1")],
    )?;
    run_env(
        "cargo",
        &["xtask", "generate-skill", "--check"],
        &[("EXA_AGENT_NO_NETWORK", "1")],
    )?;
    run(
        "cargo",
        &[
            "clippy",
            "--locked",
            "--all-targets",
            "--all-features",
            "--",
            "-D",
            "warnings",
        ],
    )?;
    run("cargo", &["test", "--workspace", "--locked"])?;
    println!("ci: OK");
    Ok(())
}

