fn smoke(args: &[String]) -> Result<()> {
    let budget = parse_smoke_budget(args)?;
    let commands = [
        (
            &[
                "run",
                "--quiet",
                "--bin",
                "exa-agent",
                "--",
                "search",
                "exa smoke test",
                "--num-results",
                "1",
                "--compact",
            ][..],
            "search",
        ),
        (
            &[
                "run",
                "--quiet",
                "--bin",
                "exa-agent",
                "--",
                "contents",
                "https://exa.ai",
                "--text",
                "--compact",
            ][..],
            "contents",
        ),
    ];
    let mut total = 0.0;
    for (command, label) in commands {
        let value = run_json_value("cargo", command, "exa.cli.response.v1")
            .with_context(|| format!("live smoke failed for {label}"))?;
        total += value
            .pointer("/costDollars/total")
            .and_then(serde_json::Value::as_f64)
            .unwrap_or(0.0);
        if total > budget {
            bail!("live smoke cost {total:.6} exceeded budget {budget:.6}");
        }
    }
    println!("smoke: OK live read-only costDollars.total={total:.6} budget={budget:.6}");
    Ok(())
}

fn parse_smoke_budget(args: &[String]) -> Result<f64> {
    let mut budget = 0.05;
    let mut iter = args.iter();
    while let Some(arg) = iter.next() {
        match arg.as_str() {
            "--budget" => {
                let Some(value) = iter.next() else {
                    bail!("--budget requires a numeric value");
                };
                budget = value
                    .parse::<f64>()
                    .with_context(|| format!("parse --budget {value:?}"))?;
            }
            other => bail!("unknown smoke argument: {other}"),
        }
    }
    if !(budget.is_finite() && budget >= 0.0) {
        bail!("--budget must be a finite non-negative number");
    }
    Ok(budget)
}

