fn run_json(cmd: &str, args: &[&str], expected_schema: &str) -> Result<()> {
    run_json_value(cmd, args, expected_schema).map(|_| ())
}

fn run_json_offline(cmd: &str, args: &[&str], expected_schema: &str) -> Result<()> {
    run_json_value_offline(cmd, args, expected_schema).map(|_| ())
}

fn run_json_value(cmd: &str, args: &[&str], expected_schema: &str) -> Result<serde_json::Value> {
    run_json_value_with_network_guard(cmd, args, expected_schema, false)
}

fn run_json_value_offline(
    cmd: &str,
    args: &[&str],
    expected_schema: &str,
) -> Result<serde_json::Value> {
    run_json_value_with_network_guard(cmd, args, expected_schema, true)
}

fn run_json_value_with_network_guard(
    cmd: &str,
    args: &[&str],
    expected_schema: &str,
    no_network: bool,
) -> Result<serde_json::Value> {
    eprintln!("$ {cmd} {}", args.join(" "));
    let mut command = Command::new(cmd);
    command.args(args).env("SOURCE_DATE_EPOCH", "1782777600");
    if no_network {
        command.env("EXA_AGENT_NO_NETWORK", "1");
    }
    let output = command.output().with_context(|| format!("spawn {cmd}"))?;
    if !output.status.success() {
        bail!(
            "{cmd} {} failed ({})\nstdout:\n{}\nstderr:\n{}",
            args.join(" "),
            output.status,
            String::from_utf8_lossy(&output.stdout),
            String::from_utf8_lossy(&output.stderr)
        );
    }
    let value: serde_json::Value = serde_json::from_slice(&output.stdout).with_context(|| {
        format!(
            "{cmd} {} did not emit JSON on stdout:\n{}",
            args.join(" "),
            String::from_utf8_lossy(&output.stdout)
        )
    })?;
    let schema = value
        .get("schema")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("");
    if schema != expected_schema {
        bail!(
            "{cmd} {} emitted schema `{schema}`, expected `{expected_schema}`",
            args.join(" ")
        );
    }
    Ok(value)
}

fn run(cmd: &str, args: &[&str]) -> Result<()> {
    run_env(cmd, args, &[])
}

fn run_env(cmd: &str, args: &[&str], envs: &[(&str, &str)]) -> Result<()> {
    eprintln!("$ {cmd} {}", args.join(" "));
    let mut command = Command::new(cmd);
    command.args(args);
    for (key, value) in envs {
        command.env(key, value);
    }
    let status = command.status().with_context(|| format!("spawn {cmd}"))?;
    if !status.success() {
        bail!("{cmd} {} failed ({status})", args.join(" "));
    }
    Ok(())
}
